#!/usr/bin/env bash
set -euo pipefail

TARGET_ROOT_DEFAULT="/Users/lipan/.nvm/versions/node/v22.22.2/lib/node_modules/remodex"
TARGET_ROOT="${1:-$TARGET_ROOT_DEFAULT}"

log() {
  echo "[install-global-remodex-sync] $*"
}

die() {
  echo "[install-global-remodex-sync] $*" >&2
  exit 1
}

decode_base64_to_file() {
  local target_path="$1"
  local temp_path
  temp_path="$(mktemp)"

  if base64 --decode >/dev/null 2>&1 <<'EOF'
QQ==
EOF
  then
    base64 --decode >"$temp_path"
  else
    base64 -D >"$temp_path"
  fi

  mv "$temp_path" "$target_path"
}

install_file() {
  local relative_path="$1"
  local mode="$2"
  local target_path="${TARGET_ROOT}/${relative_path}"
  local parent_dir
  parent_dir="$(dirname "$target_path")"

  [[ -d "$parent_dir" ]] || die "目标目录不存在: $parent_dir"

  decode_base64_to_file "$target_path"
  chmod "$mode" "$target_path"
  log "已覆盖 ${relative_path}"
}

main() {
  [[ -d "$TARGET_ROOT" ]] || die "目标 remodex 目录不存在: $TARGET_ROOT"
  log "目标目录: $TARGET_ROOT"

  install_file "bin/remodex.js" 755 <<'EOF'

EOF

  install_file "src/bridge.js" 644 <<'EOF'

EOF

  install_file "src/codex-desktop-refresher.js" 644 <<'EOF'

EOF

  install_file "src/git-handler.js" 644 <<'EOF'

EOF

  log "完成。建议随后执行一次: remodex status"
}

main "$@"
